const staticData = $getWorkflowStaticData('global');

function randomHex(len) {
  let s = '';
  while (s.length < len) {
    const r = Math.random().toString(16).substring(2);
    s += r;
  }
  return s.substring(0, len);
}

const job_id = randomHex(16);

staticData.job_id = job_id;
staticData.pipeline_started_at = new Date().toISOString();
staticData.phase = 'phase_1_complete';

return [{
  json: {
    job_id,
    pipeline_started_at: staticData.pipeline_started_at,
    trigger_source: $input.first().json?.message?.text 
      ? 'telegram_manual' 
      : 'schedule'
  }
}];

const items = $input.all();
let youtubeData = null, redditData = null, serpData = null;
for (const item of items) {
  const d = item.json;
  if (d.items && d.items[0]?.snippet?.channelId !== undefined) {
    youtubeData = d.items.map(v => ({ title: v.snippet.title, channel: v.snippet.channelTitle }));
  } else if (d.data?.children) {
    redditData = d.data.children.map(p => ({ title: p.data.title, upvotes: p.data.ups }));
  } else if (d.interest_over_time || d.related_queries) {
    serpData = { interest: d.interest_over_time?.timeline_data?.slice(-3) || [], related: d.related_queries?.rising?.slice(0, 5) || [] };
  }
}
const allFailed = !youtubeData && !redditData && !serpData;
return [{ json: { job_id: $('Generate job_id').first().json.job_id, youtube_data: youtubeData || [], reddit_data: redditData || [], serp_data: serpData || {}, all_failed: allFailed, sources_available: [youtubeData ? 'youtube' : null, redditData ? 'reddit' : null, serpData ? 'serp' : null].filter(Boolean) } }];

