// Reply comes in via webhook resume — body is in $json.body
$workflow.staticData = $workflow.staticData || {};
const reply = ($json.body?.message?.text || '').trim();
const job_id = $workflow.staticData.job_id;
const ideas = $workflow.staticData.ideas || [];

if (!reply || reply === '/skip') {
  return [{ json: { action: 'cancel', job_id } }];
}

const num = parseInt(reply);
if (num >= 1 && num <= 5 && ideas[num - 1]) {
  const chosen = ideas[num - 1];
  $workflow.staticData.chosen_topic = chosen.title;
  $workflow.staticData.chosen_topic_summary = chosen.topic_summary;
  $workflow.staticData.phase = 'phase_3_complete';
  return [{ json: {
    action: 'proceed',
    topic: chosen.title,
    topic_summary: chosen.topic_summary,
    job_id
  }}];
}

// Custom topic typed by operator
$workflow.staticData.chosen_topic = reply;
$workflow.staticData.chosen_topic_summary = '';
$workflow.staticData.phase = 'phase_3_complete';
return [{ json: {
  action: 'proceed',
  topic: reply,
  topic_summary: '',
  job_id
}}];

// Persist chosen topic for Phase 4
