// Catch upstream HTTP errors
if (response.statusCode >= 400 || response.error) {
  return [{ json: {
    error: true,
    final_failure: false,
    message: 'Claude API error: ' + (response.statusCode || response.error),
    raw: null,
    job_id
  }}];
}

let script;
try {
  const raw = response.content[0].text;
  const cleaned = raw.replace(/```json|```/g, '').trim();
  script = JSON.parse(cleaned);
} catch(e) {
  const raw = response.content?.[0]?.text || 'No content';
  return [{ json: {
    error: true,
    final_failure: false,
    message: 'JSON parse failed: ' + e.message,
    raw,
    job_id
  }}];
}

// Structural checks
if (!script.scenes || !Array.isArray(script.scenes) || script.scenes.length < 15) {
  return [{ json: {
    error: true,
    final_failure: false,
    message: 'Too few scenes: ' + (script.scenes?.length || 0),
    raw: JSON.stringify(script).substring(0, 500),
    job_id
  }}];
}

const totalDuration = script.scenes.reduce((sum, s) => sum + (s.duration_seconds || 0), 0);
if (totalDuration < 240 || totalDuration > 420) {
  return [{ json: {
    error: true,
    final_failure: false,
    message: 'Duration out of range: ' + totalDuration + 's (expected 240-420)',
    raw: JSON.stringify(script).substring(0, 500),
    job_id
  }}];
}

if (!script.full_narration || script.full_narration.length < 500) {
  return [{ json: {
    error: true,
    final_failure: false,
    message: 'Narration too short: ' + (script.full_narration?.length || 0) + ' chars',
    raw: JSON.stringify(script).substring(0, 500),
    job_id
  }}];
}

// Marker checks
const hasHook    = script.scenes.some(s => s.clip_marker === 'HOOK');
const hasClimax  = script.scenes.some(s => s.clip_marker === 'CLIMAX');
const hasEnding  = script.scenes.some(s => s.clip_marker === 'ENDING');
if (!hasHook || !hasClimax || !hasEnding) {
  return [{ json: {
    error: true,
    final_failure: false,
    message: 'Missing scene markers. HOOK:' + hasHook + ' CLIMAX:' + hasClimax + ' ENDING:' + hasEnding,
    raw: JSON.stringify(script).substring(0, 500),
    job_id
  }}];
}

return [{ json: { error: false, final_failure: false, script, totalDuration, job_id } }];

