  }}];
}

let script;
try {
  const raw = response.content[0].text;
  const cleaned = raw.replace(/```json|```/g, '').trim();
  script = JSON.parse(cleaned);
} catch(e) {
  const raw = response.content?.[0]?.text || 'No content';
  return [{ json: {
    error: true,
    final_failure: true,
    message: 'Retry JSON parse failed: ' + e.message,
    raw_output: raw,
    job_id
  }}];
}

const hasScenes = script.scenes && Array.isArray(script.scenes) && script.scenes.length >= 15;
const totalDuration = script.scenes?.reduce((sum, s) => sum + (s.duration_seconds || 0), 0) || 0;
const durationOk = totalDuration >= 240 && totalDuration <= 420;
const narrationOk = script.full_narration && script.full_narration.length >= 500;

if (!hasScenes || !durationOk || !narrationOk) {
  const raw = JSON.stringify(script).substring(0, 3000);
  return [{ json: {
    error: true,
    final_failure: true,
    message: 'Retry validation failed. scenes:' + (script.scenes?.length || 0) + ' dur:' + totalDuration + 's narr:' + (script.full_narration?.length || 0),
    raw_output: raw,
    job_id
  }}];
}

return [{ json: { error: false, final_failure: false, script, totalDuration, job_id } }];

