$workflow.staticData = $workflow.staticData || {};

// Operator replied to the failed-script Telegram message
// They can: /retry (generate fresh), /skip (cancel this pipeline run)
const reply = ($json.body?.message?.text || '').trim().toLowerCase();
const job_id = $workflow.staticData.job_id;

if (!reply || reply === '/skip') {
  return [{ json: { action: 'cancel', job_id } }];
}
if (reply === '/retry') {
  return [{ json: { action: 'retry', job_id } }];
}
// Any unrecognised input → cancel safely
return [{ json: { action: 'cancel', job_id } }];

$workflow.staticData = $workflow.staticData || {};

const { script, totalDuration, job_id } = $json;
$workflow.staticData.script = script;
$workflow.staticData.total_duration = totalDuration;
$workflow.staticData.phase = 'phase_4_complete';
return [{ json: { job_id, script, totalDuration } }];

$workflow.staticData = $workflow.staticData || {};

const res = $input.first().json;
const statusCode = res.$response?.statusCode || res.statusCode || 200;

if (statusCode === 429) {
  return [{ json: { tts_error: true, error_type: 'rate_limit', status: statusCode, job_id: $workflow.staticData.job_id } }];
}
if (statusCode === 401 || statusCode === 403) {
  return [{ json: { tts_error: true, error_type: 'auth_fail', status: statusCode, job_id: $workflow.staticData.job_id } }];
}
if (statusCode >= 400) {
  return [{ json: { tts_error: true, error_type: 'api_error', status: statusCode, job_id: $workflow.staticData.job_id } }];
}
return [{ json: { tts_error: false, error_type: null, job_id: $workflow.staticData.job_id } }];

