}
return [{ json: { upload_error: true, status: statusCode, job_id: $workflow.staticData.job_id } }];

$workflow.staticData = $workflow.staticData || {};

const attempt = ($workflow.staticData.r2_upload_attempt || 0) + 1;
$workflow.staticData.r2_upload_attempt = attempt;
const job_id = $workflow.staticData.job_id;
const backoffSeconds = [5, 15, 45];

if (attempt > 3) {
  return [{ json: { give_up: true, attempt, job_id } }];
}
return [{ json: { give_up: false, attempt, waitSeconds: backoffSeconds[attempt - 1] || 45, job_id } }];

